function useCountdown(target){
  const[t,setT]=useState({d:0,h:0,m:0,s:0});
  useEffect(()=>{const c=()=>{const diff=Math.max(0,new Date(target)-Date.now());setT({d:Math.floor(diff/864e5),h:Math.floor(diff%864e5/36e5),m:Math.floor(diff%36e5/6e4),s:Math.floor(diff%6e4/1e3)})};c();const i=setInterval(c,1000);return()=>clearInterval(i)},[target]);
  return t;
}

function useInView(th=0.12){
  const ref=useRef(null);const[v,setV]=useState(false);
  useEffect(()=>{if(!ref.current)return;const o=new IntersectionObserver(([e])=>{if(e.isIntersecting){setV(true);o.disconnect()}},{threshold:th});o.observe(ref.current);return()=>o.disconnect()},[]);
  return[ref,v];
}

function AnimNum({value,suffix=""}){
  const[ref,vis]=useInView();const[d,setD]=useState(0);
  useEffect(()=>{if(!vis)return;const n=parseInt(value),dur=1400,s=Date.now(),tick=()=>{const p=Math.min(1,(Date.now()-s)/dur),e=1-Math.pow(1-p,4);setD(Math.round(n*e));if(p<1)requestAnimationFrame(tick)};tick()},[vis,value]);
  return<span ref={ref}>{d}{suffix}</span>;
}

function FadeIn({children,delay=0,bg,style={}}){
  const[ref,v]=useInView(0.06);
  return<section ref={ref} style={{padding:"80px 16px",background:bg||"transparent",opacity:v?1:0,transform:v?"translateY(0)":"translateY(40px)",transition:`opacity 0.8s ease ${delay}s, transform 0.8s ease ${delay}s`,...style}}>{children}</section>;
}

